backgroundColor:
{{
  (() => {
    const asset = GetAssetById.data?.[0];

    if (!asset) return "#cccccc";

    const erasureStatus = (asset.erasure_status || "").toString().trim().toLowerCase();

    const isErased =
      erasureStatus === "e" ||
      erasureStatus === "erased" ||
      erasureStatus === "sanitised" ||
      erasureStatus === "sanitized" ||
      erasureStatus === "successful" ||
      erasureStatus === "success";

    const isDataBearing =
      asset.data_bearing === true ||
      asset.data_bearing === "true" ||
      asset.data_bearing === "t" ||
      asset.data_bearing === 1;

    if (isErased) return "#4dff4d";       // green
    if (isDataBearing) return "#ff4d4d";  // red
    return "#4dff4d";                     // green
  })()
}}

text:
{{
  (() => {
    const asset = GetAssetById.data?.[0];

    if (!asset) return "";

    const erasureStatus = (asset.erasure_status || "").toLowerCase();
    const hddValue = (asset.hdd || "").trim().toLowerCase();

    const isErased =
      erasureStatus === "e" ||
      erasureStatus === "erased" ||
      erasureStatus === "sanitised" ||
      erasureStatus === "successful";

    const noHardDrive =
      hddValue === "no hard drive" ||
      hddValue === "no hdd";

    if (isErased) return "SANITISED";

    if (noHardDrive) return "NON-DATA";

    if (asset.data_bearing === true) return "DATA BEARING";

    return "NON-DATA";
  })()
}}
